SELECT  NVL(MAX(SORT_ORDR), 0) + 1 AS NTT_NO
  FROM  TB_BBS
 WHERE  BBS_ID = #{bbsId}

INSERT  INTO TB_BBS
      ( NTT_ID
      , BBS_ID
      , NTT_SJ
      , NTT_CN
      , SORT_ORDR
      , NTCR_ID
      , NTCR_NM
      , PASSWORD
      , RDCNT
      , NTCE_BGNDE
      , NTCE_ENDDE
      , ANSWER_AT
      , PARNTSCTT_NO
      , NTT_NO
      , ANSWER_LC
      , ATCH_FILE_ID
      , FRST_REGISTER_ID
      , FRST_REGIST_PNTTM
      , USE_AT )
VALUES  ( #{nttId}
        , #{bbsId}
        , #{nttSj}
        , #nttCn:CLOB#
        , #{nttNo}
        , #{ntcrId}
        , #{ntcrNm}
        , #{password}
        , #{inqireCo}
        , #{ntceBgnde}
        , #{ntceEndde}
        , #{replyAt}
        , #{parnts}
        , 1
        , #{replyLc}
        , #{atchFileId}
        , #{frstRegisterId}
        , SYSDATE
        , 'Y' )


SELECT  NVL(MAX(NTT_NO), 0) + 1 AS NTT_NO
  FROM  TB_BBS
 WHERE  BBS_ID = #{bbsId}
   AND  SORT_ORDR = #{sortOrdr}

