mapper.select:
SELECT /* TODO: 컬럼 명시 필요 */ * FROM ( SELECT ROWNUM RN , TB.* FROM ( SELECT A.NTT_ID , A.NTT_SJ , A.FRST_REGISTER_ID , NVL(B.USER_NM, A.NTCR_NM) AS FRST_REGISTER_NM , TO_CHAR(A.FRST_REGIST_PNTTM, 'YYYY-MM-DD') AS FRST_REGIST_PNTTM , A.RDCNT , A.PARNTSCTT_NO , A.ANSWER_AT , A.ANSWER_LC , A.USE_AT , A.ATCH_FILE_ID , A.BBS_ID , A.NTCE_BGNDE , A.NTCE_ENDDE FROM TB_BBS A LEFT OUTER JOIN VW_USER_MASTER B ON A.FRST_REGISTER_ID = B.ESNTL_ID WHERE A.BBS_ID = #{bbsId}
AND A.USE_AT = #{useAt}
AND A.NTT_SJ LIKE '%' || #{searchWrd} || '%'
AND A.NTT_CN LIKE '%' || #{searchWrd} || '%'
AND B.USER_NM LIKE '%' || #{searchWrd} || '%'
ORDER BY A.SORT_ORDR DESC, NTT_NO ASC ) TB ) WHERE RN BETWEEN #{firstIndex} + 1 AND #{firstIndex} + #{recordCountPerPage}

SELECT COUNT(A.NTT_ID) AS cnt FROM TB_BBS A LEFT OUTER JOIN VW_USER_MASTER B ON A.FRST_REGISTER_ID = B.ESNTL_ID WHERE A.BBS_ID = #{bbsId}
AND A.USE_AT = #{useAt}
AND A.NTT_SJ LIKE '%' || #{searchWrd} || '%'
AND A.NTT_CN LIKE '%' || #{searchWrd} || '%'
AND B.USER_NM LIKE '%' || #{searchWrd} || '%'

