UPDATE  TB_BBS
   SET  NTT_SJ          = #{nttSj}
      , NTT_CN          = #nttCn:CLOB#
      , NTCR_ID         = #{ntcrId}
      , NTCR_NM         = #{ntcrNm}
      , PASSWORD        = #{password}
      , NTCE_BGNDE      = #{ntceBgnde}
      , NTCE_ENDDE      = #{ntceEndde}
      , LAST_UPDUSR_ID  = #{lastUpdusrId}
      , ATCH_FILE_ID    = #{atchFileId}
      , LAST_UPDT_PNTTM = SYSDATE
 WHERE  BBS_ID = #{bbsId}
   AND  NTT_ID = #{nttId}

UPDATE  TB_BBS
   SET  NTT_SJ          = #{nttSj}
      , USE_AT          = 'N'
      , LAST_UPDUSR_ID  = #{lastUpdusrId}
      , LAST_UPDT_PNTTM = SYSDATE
 WHERE  BBS_ID = #{bbsId}
   AND  NTT_ID = #{nttId}

